def test_local_app_artifact_viewer_is_read_only_and_bounded(
    tmp_path: Path,
) -> None:
    AgentSystem(tmp_path).initialize()
    verification_without_ci = render_local_app_route(tmp_path, "/verification")
    assert verification_without_ci.status == 200
    assert "Latest Recorded CI Evidence" in verification_without_ci.body
    assert "latest_ci_status: missing" in verification_without_ci.body
    assert "record_command_template: python3 -m agent_os.cli ci-deploy-evidence" in verification_without_ci.body
    assert "github_status_fetch: none" in verification_without_ci.body
    ci_evidence_without_handoff = render_local_app_route(tmp_path, "/ci-evidence")
    assert ci_evidence_without_handoff.status == 200
    assert "CI Evidence Recording Guide" in ci_evidence_without_handoff.body
    assert "latest_github_handoff: missing" in ci_evidence_without_handoff.body
    assert "record_command_template: unavailable_until_github_handoff_exists" in ci_evidence_without_handoff.body
    assert "direct_snapshot_handoff_command_template" in ci_evidence_without_handoff.body
    assert "ci-snapshot-handoff" in ci_evidence_without_handoff.body
    assert "direct_snapshot_record_command_template" in ci_evidence_without_handoff.body
    assert "ci-snapshot-evidence" in ci_evidence_without_handoff.body
    assert "proof_boundary: operator_supplied_record_only" in ci_evidence_without_handoff.body
    docs = tmp_path / "docs"
    docs.mkdir(exist_ok=True)
    (docs / "sample.md").write_text("# Sample\n", encoding="utf-8")
    (docs / "sample.json").write_text('{"ok": true}\n', encoding="utf-8")
    (docs / "sample.txt").write_text("plain text\n", encoding="utf-8")
    (docs / "sample.patch").write_text("--- a/demo.txt\n+++ b/demo.txt\n", encoding="utf-8")
    (docs / "sample.diff").write_text("diff --git a/demo.txt b/demo.txt\n", encoding="utf-8")
    (docs / "sample.log").write_text("demo log line\n", encoding="utf-8")

    markdown = render_local_app_route(tmp_path, "/artifacts?path=docs/sample.md")
    assert markdown.status == 200
    assert "artifact_type" in markdown.body
    assert "markdown" in markdown.body
    assert "# Sample" in markdown.body
    json_response = render_local_app_route(tmp_path, "/artifacts?path=docs/sample.json")
    assert json_response.status == 200
    assert "json" in json_response.body
    assert "&quot;ok&quot;: true" in json_response.body
    text_response = render_local_app_route(tmp_path, "/artifacts?path=docs/sample.txt")
    assert text_response.status == 200
    assert "text" in text_response.body
    assert "plain text" in text_response.body
    patch_response = render_local_app_route(tmp_path, "/artifacts?path=docs/sample.patch")
    assert patch_response.status == 200
    assert "patch" in patch_response.body
    assert "--- a/demo.txt" in patch_response.body
    diff_response = render_local_app_route(tmp_path, "/artifacts?path=docs/sample.diff")
    assert diff_response.status == 200
    assert "diff" in diff_response.body
    assert "diff --git" in diff_response.body
    log_response = render_local_app_route(tmp_path, "/artifacts?path=docs/sample.log")
    assert log_response.status == 200
    assert "log" in log_response.body
    assert "demo log line" in log_response.body

    absolute = render_local_app_route(
        tmp_path,
        f"/artifacts?path={tmp_path / 'docs' / 'sample.md'}",
    )
    assert absolute.status == 400
    assert "absolute artifact paths are rejected" in absolute.body
    traversal = render_local_app_route(tmp_path, "/artifacts?path=../README.md")
    assert traversal.status == 400
    assert "parent traversal is rejected" in traversal.body

    outside = tmp_path.parent / f"{tmp_path.name}-outside.txt"
    outside.write_text("outside\n", encoding="utf-8")
    symlink = docs / "outside.txt"
    symlink.symlink_to(outside)
    outside_link = render_local_app_route(tmp_path, "/artifacts?path=docs/outside.txt")
    assert outside_link.status == 400
    assert "outside repo root" in outside_link.body

    assert resolve_artifact_path(tmp_path, "docs/sample.md") == docs / "sample.md"


