def test_coder_publication_request_blocks_tampered_commit_artifact(
    tmp_path: Path,
    capsys,
) -> None:
    (
        _source_run_id,
        _delegation_id,
        _approval_id,
        run_id,
        evidence_dir,
        _worktree_path,
        _repo_path,
        _commit_sha,
        _parent_sha,
        _branch_name,
    ) = _commit_completed_coder_worktree(tmp_path, capsys)
    commit_artifact = evidence_dir / "coder_commit" / "commit.json"
    commit_payload = json.loads(commit_artifact.read_text(encoding="utf-8"))

    missing_sha_payload = {**commit_payload, "commit_sha": ""}
    commit_artifact.write_text(
        json.dumps(missing_sha_payload, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "coder-publication-request",
                run_id,
                "--requested-by",
                "operator",
                "--remote",
                "origin",
                "--target-branch",
                "main",
                "--note",
                "should fail",
            ]
        )
        == 1
    )
    missing_sha_output = capsys.readouterr().out
    assert "coder_publication_request_failed: commit_sha_missing" in missing_sha_output

    bad_sha_payload = {**commit_payload, "commit_sha": "a" * 40}
    commit_artifact.write_text(
        json.dumps(bad_sha_payload, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "coder-publication-request",
                run_id,
                "--requested-by",
                "operator",
                "--remote",
                "origin",
                "--target-branch",
                "main",
                "--note",
                "should fail",
            ]
        )
        == 1
    )
    bad_sha_output = capsys.readouterr().out
    assert "coder_publication_request_failed: commit_sha_not_found" in bad_sha_output

    outside_payload = {
        **commit_payload,
        "committed_files": [*commit_payload["committed_files"], "notes/outside.txt"],
    }
    commit_artifact.write_text(
        json.dumps(outside_payload, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "coder-publication-request",
                run_id,
                "--requested-by",
                "operator",
                "--remote",
                "origin",
                "--target-branch",
                "main",
                "--note",
                "should fail",
            ]
        )
        == 1
    )
    outside_output = capsys.readouterr().out
    assert "coder_publication_request_failed: outside_allowed_files_present" in outside_output

    for mutated_key, mutated_value in (
        ("push_created", True),
        ("pr_created", True),
        ("deploy_created", True),
        ("provider_calls_taken_by_clankeros", 1),
        ("network_actions_taken", 1),
        ("external_mutations_taken", 1),
    ):
        mutated_payload = {**commit_payload, mutated_key: mutated_value}
        commit_artifact.write_text(
            json.dumps(mutated_payload, indent=2, sort_keys=True) + "\n",
            encoding="utf-8",
        )
        assert (
            main(
                [
                    "--root",
                    str(tmp_path),
                    "coder-publication-request",
                    run_id,
                    "--requested-by",
                    "operator",
                    "--remote",
                    "origin",
                    "--target-branch",
                    "main",
                    "--note",
                    "should fail",
                ]
            )
            == 1
        )
        mutated_output = capsys.readouterr().out
        assert (
            "coder_publication_request_failed: publication_state_already_mutated"
            in mutated_output
        )


